// DETERMINISTIC inventory science (mirrors services/planning.py + forecasting.py).
// No AI here — this is the math the AI's reliability note sits ON TOP of.
const s = $json;
const lead = s.lead_time_days || 0;

// 1. Expected demand over the lead time.
const ltd = s.usage_rate_per_day * lead;

// 2. Service-level safety stock = z * sigma over lead time (sigma_daily * sqrt(lead)).
const sigma_ltd = (s.demand_sigma_per_day || 0) * Math.sqrt(lead);
const safety_stock = Math.ceil(s.service_level_z * sigma_ltd);

// 3. Dynamic reorder point + status.
const reorder_point = Math.ceil(ltd) + safety_stock;
const available = (s.on_hand || 0) + (s.on_order || 0);
const days_cover = s.usage_rate_per_day > 0 ? Math.floor(s.on_hand / s.usage_rate_per_day) : 999;

let status, action;
if (available <= safety_stock)       { status = 'reorder'; action = `ORDER NOW — below safety (${available} ≤ ${safety_stock})`; }
else if (available <= reorder_point) { status = 'low';     action = `Order soon — below reorder point (${available} ≤ ${reorder_point})`; }
else                                 { status = 'ok';      action = `Healthy — ${days_cover}d cover`; }

return [{ json: {
  sku: s.sku, product: s.product_name,
  lead_time_days: lead,
  expected_lt_demand: Math.ceil(ltd),
  safety_stock,                 // z * sigma_LTD — the upgrade over burn*lead/2
  reorder_point,                // DYNAMIC: moves with lead time + variability
  available, days_cover,
  status, action
}}];

